  ('a82c1231-94b4-5d9e-a321-bcc29a63f085'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige exactamente lo que oíste.', '{"options": ["Her argument is nuanced, though arguably a little optimistic.", "Her argument is new ones, though arguably a little optimistic.", "Her argument is nuanced, though our girl is a little optimistic."], "say": "Her argument is nuanced, though arguably a little optimistic.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/a82c1231-94b4-5d9e-a321-bcc29a63f085.mp3"}'::jsonb, '{"value": "Her argument is nuanced, though arguably a little optimistic."}'::jsonb, 0.88, ARRAY['unidad25', 'hedging_near_synonyms_co', 'listening', 'lsbal']),
  ('f88fb330-6c14-5a84-9d06-9af45a731139'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la pregunta y elige la única respuesta natural en C1.', '{"options": ["Assertive, definitely. You stood your ground without ever raising your voice or putting anyone down.", "Aggressive, obviously. You were extremely frugal with the whole budget.", "Neither, really. The report was heavily reliant on outdated figures."], "say": "Honestly, do you think I came across as assertive or just aggressive in that meeting?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/f88fb330-6c14-5a84-9d06-9af45a731139.mp3"}'::jsonb, '{"value": "Assertive, definitely. You stood your ground without ever raising your voice or putting anyone down."}'::jsonb, 0.88, ARRAY['unidad25', 'near_synonyms_con_connot', 'listening', 'lsbal']),
  ('3139b07b-2da4-57e2-ac88-8dbac837fda5'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la pregunta y elige la única respuesta natural en C1.', '{"options": ["I''d say she overstated it somewhat; the figures are arguably less impressive than she suggested.", "I''d say she was terribly stingy; she refused to tip the waiter at all.", "I''d say her attention to detail was meticulous, so the audit came out flawless."], "say": "Do you think the minister overstated the recovery, or was she being fair?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/3139b07b-2da4-57e2-ac88-8dbac837fda5.mp3"}'::jsonb, '{"value": "I''d say she overstated it somewhat; the figures are arguably less impressive than she suggested."}'::jsonb, 0.88, ARRAY['unidad25', 'overstate_hedging_en_val', 'listening', 'lsbal']),
  ('c830527a-e771-5e92-9729-13f491c43a27'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "Frankly, the government tends to downplay the risks, though arguably the situation is somewhat more serious than the official figures suggest.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/c830527a-e771-5e92-9729-13f491c43a27.mp3"}'::jsonb, '{"expected": "Frankly, the government tends to downplay the risks, though arguably the situation is somewhat more serious than the official figures suggest."}'::jsonb, 0.88, ARRAY['unidad25', 'downplay_hedging_registr', 'speaking', 'lsbal']),
  ('93ba45b3-2094-516c-bd75-86e1c68adba5'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "To be candid, her proposal is compelling, but its success remains heavily reliant on funding we simply don''t have yet.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/93ba45b3-2094-516c-bd75-86e1c68adba5.mp3"}'::jsonb, '{"expected": "To be candid, her proposal is compelling, but its success remains heavily reliant on funding we simply don''t have yet."}'::jsonb, 0.88, ARRAY['unidad25', 'strong_collocations_cand', 'speaking', 'lsbal']),
  ('09164e26-cee4-5b76-bf37-2b897110b5c5'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'reading'::skill, 'multiple_choice'::content_item_type, 'Lee: "The spokesperson was decidedly blunt about the layoffs." El adverbio "decidedly" sugiere que la franqueza fue:', '{"options": ["clara y sin rodeos, casi tajante", "amable y diplomática", "dudosa e indecisa"]}'::jsonb, '{"value": "clara y sin rodeos, casi tajante"}'::jsonb, 0.88, ARRAY['unidad25', 'adverbios_de_grado_matiz', 'reading', 'eficgap']),
  ('9c9dd741-fe2f-594e-b596-aaef156d66ee'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'writing'::skill, 'cloze'::content_item_type, 'Elige el intensificador que COLOCA de forma natural con ''concerned'' en C1: "We remain ___ concerned about the situation."', '{"text": "Elige el intensificador que COLOCA de forma natural con ''concerned'' en C1: \"We remain ___ concerned about the situation.\"", "options": ["deeply", "strongly", "heavily"]}'::jsonb, '{"value": "deeply"}'::jsonb, 0.88, ARRAY['unidad25', 'selectividad_de_colocaci', 'writing', 'eficgap']),
  ('f619d302-372a-5ade-b803-ccccd9eff89f'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige exactamente la frase que oíste.', '{"options": ["Granted, the initiative is costly; nevertheless, the savings it yields over a decade more than justify the outlay.", "Granted, the initiative is cost-free; therefore, the savings it yields over a decade barely justify the outlay.", "Granted, the initiative is costly; conversely, the losses it yields over a decade hardly justify the outlay."], "say": "Granted, the initiative is costly; nevertheless, the savings it yields over a decade more than justify the outlay.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/f619d302-372a-5ade-b803-ccccd9eff89f.mp3"}'::jsonb, '{"value": "Granted, the initiative is costly; nevertheless, the savings it yields over a decade more than justify the outlay."}'::jsonb, 0.88, ARRAY['unidad26', 'admitir_para_luego_rebat', 'listening', 'lsbal']),
  ('ddb99d10-3dcf-59e4-82b5-267d832fd173'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige exactamente la frase que oíste.', '{"options": ["Notwithstanding the union''s objections, management pressed ahead, thereby setting a precedent the workforce would later resent.", "Notwithstanding the union''s approval, management pulled back, thereby setting a precedent the workforce would later welcome.", "Nevertheless the union''s objections, management pressed ahead, hence setting a precedent the workforce ignored."], "say": "Notwithstanding the union''s objections, management pressed ahead, thereby setting a precedent the workforce would later resent.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/ddb99d10-3dcf-59e4-82b5-267d832fd173.mp3"}'::jsonb, '{"value": "Notwithstanding the union''s objections, management pressed ahead, thereby setting a precedent the workforce would later resent."}'::jsonb, 0.88, ARRAY['unidad26', 'refutar_y_sostener_una_t', 'listening', 'lsbal']),
  ('7da243c5-78df-5ffd-8d1a-c59c8629bec2'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la frase y elige la única réplica que concede el punto pero lo rebate.', '{"options": ["Admittedly, it may shield some jobs in the short term; that said, it risks raising prices for every household in the region.", "Furthermore, it will shield every job permanently, so no household will ever pay a cent more.", "Conversely, it protects no jobs whatsoever, which is precisely why prices will fall."], "say": "The minister insists the new tariff will protect local jobs. How would you concede the point yet push back?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/7da243c5-78df-5ffd-8d1a-c59c8629bec2.mp3"}'::jsonb, '{"value": "Admittedly, it may shield some jobs in the short term; that said, it risks raising prices for every household in the region."}'::jsonb, 0.88, ARRAY['unidad26', 'admitir_para_luego_rebat', 'listening', 'lsbal']),
  ('efca7eba-5069-5057-b9bd-f9ba5b512cd9'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la frase y elige la única réplica que socava la afirmación atacando su premisa.', '{"options": ["The survey rests on a flawed premise: it polled only subscribers, hence it can hardly speak for the public at large.", "The survey is compelling precisely because it polled only subscribers, thereby capturing the whole public.", "I concede the survey is decisive, and conversely it proves nothing about subscribers."], "say": "Your colleague argues the survey proves public support. On what grounds could you undermine that claim?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/efca7eba-5069-5057-b9bd-f9ba5b512cd9.mp3"}'::jsonb, '{"value": "The survey rests on a flawed premise: it polled only subscribers, hence it can hardly speak for the public at large."}'::jsonb, 0.88, ARRAY['unidad26', 'oponer_ideas_y_matizar', 'listening', 'lsbal']),
  ('8f095161-0442-50ba-9145-62ed2b7a9991'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "Admittedly, his figures are striking; that said, they rest on a single survey, and one swallow does not make a summer.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/8f095161-0442-50ba-9145-62ed2b7a9991.mp3"}'::jsonb, '{"expected": "Admittedly, his figures are striking; that said, they rest on a single survey, and one swallow does not make a summer."}'::jsonb, 0.88, ARRAY['unidad26', 'admitir_para_luego_rebat', 'speaking', 'lsbal']),
  ('83794675-437f-5259-84d9-b0da56f482be'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "Whereas the report dwells on the risks, it glosses over the benefits entirely, thereby painting a picture far bleaker than the evidence warrants.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/83794675-437f-5259-84d9-b0da56f482be.mp3"}'::jsonb, '{"expected": "Whereas the report dwells on the risks, it glosses over the benefits entirely, thereby painting a picture far bleaker than the evidence warrants."}'::jsonb, 0.88, ARRAY['unidad26', 'oponer_ideas_y_matizar', 'speaking', 'lsbal']),
  ('0c0edcfd-3fd7-5a12-b029-047bc0538657'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'reading'::skill, 'multiple_choice'::content_item_type, 'Lee e infiere la estrategia retórica: "Far from weakening my case, that objection actually reinforces it: if even the critics concede the data, the conclusion is unassailable." ¿Qué hace el autor con la objeción?', '{"options": ["La reaprovecha para reforzar su propia tesis", "La acepta y abandona su tesis", "La ignora y cambia de tema"]}'::jsonb, '{"value": "La reaprovecha para reforzar su propia tesis"}'::jsonb, 0.88, ARRAY['unidad26', 'refutar_y_sostener_una_t', 'reading', 'eficgap']),
  ('b563530d-4747-5fe7-9859-eb7ee14c8d25'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige la frase que oíste.', '{"options": ["Not only had the figures been inflated, but the auditor had signed off on them anyway.", "Not only the figures had been inflated, but the auditor signed off on them anyway.", "Not only had the figures been inflated when the auditor had signed off on them anyway."], "say": "Not only had the figures been inflated, but the auditor had signed off on them anyway.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/b563530d-4747-5fe7-9859-eb7ee14c8d25.mp3"}'::jsonb, '{"value": "Not only had the figures been inflated, but the auditor had signed off on them anyway."}'::jsonb, 0.88, ARRAY['unidad27', 'inversi_n_con_not_only_b', 'listening', 'lsbal']),
  ('299b6e8e-850b-5518-a7ce-0390dcabfd45'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige la frase que oíste.', '{"options": ["It was precisely her reluctance to commit that gave the whole thing away.", "It was precisely her reluctance to commit what gave the whole thing away.", "What precisely her reluctance to commit gave the whole thing away."], "say": "It was precisely her reluctance to commit that gave the whole thing away.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/299b6e8e-850b-5518-a7ce-0390dcabfd45.mp3"}'::jsonb, '{"value": "It was precisely her reluctance to commit that gave the whole thing away."}'::jsonb, 0.88, ARRAY['unidad27', 'it_cleft_enf_tico_con_th', 'listening', 'lsbal']),
  ('8a563de4-cfba-50f7-9c4b-785f55db83e0'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la pregunta y elige la respuesta correcta.', '{"options": ["Hardly. If anything, he was quietly stalling it.", "Yes, he''ll definitely vote against it tomorrow.", "No, that''s exactly why he proposed it himself."], "say": "So, reading between the lines, would you say he was actually in favour of the merger?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/8a563de4-cfba-50f7-9c4b-785f55db83e0.mp3"}'::jsonb, '{"value": "Hardly. If anything, he was quietly stalling it."}'::jsonb, 0.88, ARRAY['unidad27', 'inferir_implicaci_n_acti', 'listening', 'lsbal']),
  ('e4cb9ad9-b91d-53ab-ab4c-baec80a9ed31'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la pregunta y elige la respuesta correcta.', '{"options": ["Almost certainly. The compliment was rather backhanded.", "Of course not. She had nothing but criticism for it.", "Probably. She refused to comment on it at all."], "say": "Wasn''t her praise just a polite way of telling us the report fell short?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/e4cb9ad9-b91d-53ab-ab4c-baec80a9ed31.mp3"}'::jsonb, '{"value": "Almost certainly. The compliment was rather backhanded."}'::jsonb, 0.88, ARRAY['unidad27', 'inferir_cr_tica_velada_i', 'listening', 'lsbal']),
  ('147b2621-0f99-5b63-8203-5ec6ea5f0a0b'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "Only by reading between the lines could the board grasp what the chairman was really implying.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/147b2621-0f99-5b63-8203-5ec6ea5f0a0b.mp3"}'::jsonb, '{"expected": "Only by reading between the lines could the board grasp what the chairman was really implying."}'::jsonb, 0.88, ARRAY['unidad27', 'inversi_n_tras_only_by_i', 'speaking', 'lsbal']),
