  ('490f5d74-2055-591b-bec5-28614502c065'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'reading'::skill, 'multiple_choice'::content_item_type, 'Elige la condicional con inversión correcta (registro formal):', '{"options": ["Were the board to reconsider, the merger might still go ahead.", "Was the board to reconsider, the merger might still go ahead.", "If the board were reconsider, the merger might still go ahead."]}'::jsonb, '{"value": "Were the board to reconsider, the merger might still go ahead."}'::jsonb, 0.88, ARRAY['unidad27', 'inversi_n_condicional_fo', 'reading', 'eficgap']),
  ('c06c3a02-c0ed-58ca-8ec4-656c6770dd52'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'writing'::skill, 'cloze'::content_item_type, 'Completa la condicional invertida formal (sin ''if''): «___ you require any further assistance, do not hesitate to contact us.»', '{"text": "Completa la condicional invertida formal (sin ''if''): «___ you require any further assistance, do not hesitate to contact us.»", "options": ["Should", "Would", "Did"]}'::jsonb, '{"value": "Should"}'::jsonb, 0.88, ARRAY['unidad27', 'inversi_n_condicional_co', 'writing', 'eficgap']),
