  ('1af695b3-11bf-5503-b43d-72e9dce7026a'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Un compañero te pregunta esto en el trabajo. Elige la única respuesta natural.', '{"options": ["Honestly, the layoffs are just the tip of the iceberg.", "Honestly, the layoffs were a blessing in disguise for the buyers.", "Honestly, we ruled out the layoffs from the very start."], "say": "Were the layoffs the whole problem, or is there more going on?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/1af695b3-11bf-5503-b43d-72e9dce7026a.mp3"}'::jsonb, '{"value": "Honestly, the layoffs are just the tip of the iceberg."}'::jsonb, 0.88, ARRAY['unidad28', 'responder_con_idiom_the_', 'listening', 'lsbal']),
