  ('a96256d6-ac36-588d-b418-8c54b38e3b48'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'reading'::skill, 'multiple_choice'::content_item_type, 'Tu colega trajo café para todos sin saber que la cafetería ya había repartido café gratis. Elige la frase que dice que SÍ trajo el café, pero no hacía falta:', '{"options": ["You needn''t have brought coffee; they were giving it out free.", "You didn''t need to bring coffee; they were giving it out free.", "You mustn''t have brought coffee; they were giving it out free."]}'::jsonb, '{"value": "You needn''t have brought coffee; they were giving it out free."}'::jsonb, 0.88, ARRAY['unidad29', 'neednt_have_vs_didnt_nee', 'reading', 'eficgap']),
