  ('3e90b4d1-eb37-562a-80e1-afda2b538bb6'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige exactamente la frase que oíste.', '{"options": ["The author concedes that the framework is, to some extent, oversimplified.", "The author concludes that the framework is, to some extent, oversimplified.", "The author conceives that the framework is, to some extent, oversimplified."], "say": "The author concedes that the framework is, to some extent, oversimplified.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/3e90b4d1-eb37-562a-80e1-afda2b538bb6.mp3"}'::jsonb, '{"value": "The author concedes that the framework is, to some extent, oversimplified."}'::jsonb, 0.88, ARRAY['unidad30', 'verbos_de_cita_academico', 'listening', 'lsbal']),
  ('02ae9afd-cc53-5d2f-84b5-f6b9e3cc44e5'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige exactamente la frase que oíste.', '{"options": ["It is widely assumed that the implementation of the policy will be gradual.", "It is widely assured that the implementation of the policy will be gradual.", "It is widely assumed that the implication of the policy will be gradual."], "say": "It is widely assumed that the implementation of the policy will be gradual.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/02ae9afd-cc53-5d2f-84b5-f6b9e3cc44e5.mp3"}'::jsonb, '{"value": "It is widely assumed that the implementation of the policy will be gradual."}'::jsonb, 0.88, ARRAY['unidad30', 'pasiva_impersonal_academ', 'listening', 'lsbal']),
  ('b7b63b9d-5a3e-54dc-858f-f45c95e09328'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la objeción de un colega en un seminario. Elige la réplica académica adecuada.', '{"options": ["You raise a fair point; I concede that the evidence stops short of establishing causation.", "Yes, the implementation of the policy was delayed by two years.", "I''m not sure, the library closes at eight tonight."], "say": "Your paper claims a causal link, but couldn''t the relationship simply be correlational?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/b7b63b9d-5a3e-54dc-858f-f45c95e09328.mp3"}'::jsonb, '{"value": "You raise a fair point; I concede that the evidence stops short of establishing causation."}'::jsonb, 0.88, ARRAY['unidad30', 'verbos_de_cita_academico', 'listening', 'lsbal']),
  ('e90e940a-8543-5d06-b347-18b25c92159e'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la pregunta de un revisor. Elige la réplica que matiza el alcance.', '{"options": ["They hold to a large extent, with the exception of the youngest cohort.", "They are widely regarded as obsolete by everyone in the field.", "I acknowledge that I have never read the original study."], "say": "To what extent do your conclusions hold across the different age groups?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/e90e940a-8543-5d06-b347-18b25c92159e.mp3"}'::jsonb, '{"value": "They hold to a large extent, with the exception of the youngest cohort."}'::jsonb, 0.88, ARRAY['unidad30', 'matizar_y_conectar_ideas', 'listening', 'lsbal']),
  ('131d4555-261c-5cbd-a6e6-c82868db79c6'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "It has been argued that the introduction of the framework brought about a marked improvement, though several findings warrant further scrutiny.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/131d4555-261c-5cbd-a6e6-c82868db79c6.mp3"}'::jsonb, '{"expected": "It has been argued that the introduction of the framework brought about a marked improvement, though several findings warrant further scrutiny."}'::jsonb, 0.88, ARRAY['unidad30', 'pasiva_impersonal_academ', 'speaking', 'lsbal']),
  ('98cf0ba7-a4fd-5e7e-9aea-9eff8fd855af'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "While the study acknowledges its limitations, it nonetheless contends that the underlying trend holds to a considerable extent.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/98cf0ba7-a4fd-5e7e-9aea-9eff8fd855af.mp3"}'::jsonb, '{"expected": "While the study acknowledges its limitations, it nonetheless contends that the underlying trend holds to a considerable extent."}'::jsonb, 0.88, ARRAY['unidad30', 'matizar_y_conectar_ideas', 'speaking', 'lsbal']),
  ('27982894-21cd-5fef-bc65-c9d12bbadcce'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'C1'::cefr_level, 'reading'::skill, 'multiple_choice'::content_item_type, 'Elige la versión con cobertura modal (hedging) más propia del registro académico C1:', '{"options": ["It would appear that the intervention may well account for the observed gains.", "The intervention definitely accounts for the observed gains, no doubt about it.", "I think maybe the intervention is the reason for the gains, probably."]}'::jsonb, '{"value": "It would appear that the intervention may well account for the observed gains."}'::jsonb, 0.88, ARRAY['unidad30', 'matizar_y_conectar_ideas', 'reading', 'eficgap']),
